import json,re
d=json.load(open('/tmp/fullscan.json'))
# Build map pkg -> {versions, ghsa list, fix versions, severity}
from collections import defaultdict
pkgs=defaultdict(lambda:{'ghsa':[],'fixes':set(),'sev':set(),'states':set()})
for f in d['findings']:
    fid=f.get('id','')
    if not fid.startswith('GHSA'): continue
    p=f['package']; key=p['name']+'@'+str(p['version'])
    e=pkgs[key]
    e['ghsa'].append(fid); e['sev'].add(f.get('severity'))
    for r in f.get('reasons',[]):
        m=re.search(r'upgrade to ([0-9][^ ]*)',r)
        if m: e['fixes'].add(m.group(1))
        if 'Fix state:' in r: e['states'].add(r.split('Fix state:')[1].strip())
        if r.startswith('No fix') or 'no fix' in r.lower(): e['states'].add('NOFIX')
print('DISTINCT vulnerable pkgs:', len(pkgs))
for k in sorted(pkgs):
    e=pkgs[k]
    print(f'{k}')
    print(f'   sev={sorted(e[\"sev\"])} fixes={sorted(e[\"fixes\"])} states={e[\"states\"]} n={len(e[\"ghsa\"])}')
"

